}
```

```hcl
resource "aws_security_group" "web_bastion_sg" {
  name        = "web-bastion-sg"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = [aws_eip.bastion.public_ip]  # Dépendance circulaire à gérer avec `depends_on` ou en dissociant
  }

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}
```
(Remarque : pour éviter la dépendance circulaire, on peut créer la SG sans la règle SSH bastion puis l’attacher après, ou utiliser une règle avec `self` ou un groupe de sécurité dédié).
